INSERT INTO events (id, title, type, description, poster_url, genre, duration_minutes, age_rating, rating, source_name, stripe_product_id, created_at) VALUES (1, 'Дюна: Пророчество', 'movie', 'Эпическая научная фантастика о зарождении ордена Бене Гессерит за десять тысяч лет до событий Пола Атрейдеса.', 'https://static.kinoafisha.info/k/series_posters/220/upload/series/posters/9/2/3/4329/699231631128.jpg', 'Фантастика', 165, '16+', 8.7, 'Кинопоиск Афиша', NULL, '2026-07-11 23:02:23.088524+00'), (2, 'Легенда о драконе', 'movie', 'Фэнтезийное приключение о молодом кузнеце, который должен пробудить древнего дракона-хранителя.', 'https://upload.wikimedia.org/wikipedia/ru/8/82/%D0%9B%D0%B5%D0%B3%D0%B5%D0%BD%D0%B4%D0%B0_%D0%BE_%D0%9A%D1%80%D0%B0%D1%81%D0%BD%D0%BE%D0%BC_%D0%B4%D1%80%D0%B0%D0%BA%D0%BE%D0%BD%D0%B5.jpg', 'Фэнтези', 128, '12+', 7.9, 'Афиша.ру', NULL, '2026-07-11 23:02:23.15374+00'), (3, 'Полуночный экспресс', 'movie', 'Напряжённый триллер о пассажирах ночного поезда, застрявших с убийцей среди них.', 'https://resizer.mail.ru/p/57f22168-7f8f-56b1-b97e-28aaa65ca2c2/AQACvXG1nWXnmwHlYDvVZTP-VW5G83a60Vy0fuxN3oMHvky4MSVmLeBhZNByP33pMqbO05FfSBPO3dc-8OCK2D_lwq8.jpg', 'Триллер', 110, '18+', 8.1, 'Kassir.ru', NULL, '2026-07-11 23:02:23.186723+00'), (4, 'Смешные истории 3', 'movie', 'Третья часть народной комедийной франшизы о нелепых приключениях большой семьи.', 'https://upload.wikimedia.org/wikipedia/ru/f/fe/%D0%9F%D0%BE%D1%87%D1%82%D0%B8_%D1%81%D0%BC%D0%B5%D1%88%D0%BD%D0%B0%D1%8F_%D0%B8%D1%81%D1%82%D0%BE%D1%80%D0%B8%D1%8F.jpg', 'Комедия', 95, '6+', 7.2, 'Билетик.ру', NULL, '2026-07-11 23:02:23.223983+00'), (5, 'Космический патруль', 'movie', 'Семейная анимация о команде юных космонавтов, спасающих галактику от забавных злодеев.', 'http://www.mirserialov.ru/system/files/imagecache/post_images_gallery/cf46353cdb62.jpg', 'Анимация', 90, '6+', 8.4, 'Афиша.ру', NULL, '2026-07-11 23:02:23.270318+00'), (6, 'Чайка', 'theater', 'Классическая драма А. П. Чехова о любви, творчестве и несбывшихся мечтах.', 'https://s5.afisha.ru/mediastorage/16/e1/c4163d1f82a64e1f9aa28e4de116.jpg', 'Драма', 150, '12+', 9.1, 'Kassir.ru', NULL, '2026-07-11 23:02:23.309102+00'), (7, 'Ревизор', 'theater', 'Бессмертная сатирическая комедия Н. В. Гоголя о чиновничьих нравах уездного города.', 'https://s2.afisha.ru/mediastorage/62/84/a0cdca01f0fb4c5c8bc2d3b08462.jpg', 'Комедия', 140, '12+', 8.6, 'Билетик.ру', NULL, '2026-07-11 23:02:23.357315+00'), (8, 'Лебединое озеро', 'theater', 'Легендарный балет П. И. Чайковского о заколдованной принцессе-лебеди в исполнении ведущей труппы.', 'https://s.afisha.ru/mediastorage/1c/63/08158273eef145fe96f94351631c.png', 'Балет', 120, '6+', 9.4, 'Афиша.ру', NULL, '2026-07-11 23:02:23.412645+00'), (9, 'Гамлет', 'theater', 'Шекспировская трагедия о датском принце, мести и цене истины, в новой сценической редакции.', 'https://s1.afisha.ru/mediastorage/4b/0e/ab797fb7c21b440f829e6f8f0e4b.jpg', 'Трагедия', 180, '16+', 8.9, 'Kassir.ru', NULL, '2026-07-11 23:02:23.463227+00'), (10, 'Пила X', 'movie', 'Десятая часть культового хоррор-франчайза о изощрённых ловушках маньяка Джона Крамера.', 'https://www.soyuz.ru/public/uploads/files/5/7628351/1005x558_2023100221214098f27129f5.jpg', 'Ужасы', 118, '18+', 7.6, 'Kino Mail', NULL, '2026-07-11 23:02:23.512378+00'), (11, 'Балерина', 'movie', 'Боевик-спин-офф о девушке из мира наёмных убийц, ищущей возмездия за гибель семьи.', 'https://www.kinonews.ru/insimgs/2025/poster/thumbs/poster134506_2.webp', 'Боевик', 125, '18+', 7.8, 'Афиша.ру', NULL, '2026-07-11 23:02:23.547307+00'), (12, 'Нейробатя', 'movie', 'Российская комедия о неловком отце, который пытается наладить контакт с дочерью через ИИ-помощника.', 'https://kinobusiness.com/upload/resize_cache/iblock/c39/973vaizu8c5q73qqoyr3km7524dha1i9/360_560_1/image-_1_.jpg', 'Комедия', 100, '12+', 7.3, 'Sobaka.ru', NULL, '2026-07-11 23:02:23.585841+00'), (13, 'Ночной трамвай', 'theater', 'Спектакль-променад по ночному городу, где зрители становятся пассажирами странного маршрута судьбы.', 'https://kuda-kazan.ru/image/185/185//uploads/bfee4a145fb5c27b010f31a1429ca41b.jpg', 'Иммерсивный спектакль', 90, '16+', 8.5, 'Kazan-tuz.ru', NULL, '2026-07-11 23:02:23.627338+00'), (14, 'Ночь её откровений', 'theater', 'Искромётная комедия положений о женщине, решившей за одну ночь рассказать всю правду близким.', 'https://s4.afisha.ru/mediastorage/72/9d/049374a342604926b229269f9d72.jpg', 'Комедия', 130, '16+', 9.1, 'Афиша.ру', NULL, '2026-07-11 23:02:23.67335+00'), (15, 'Подыскиваю жену, недорого!', 'theater', 'Водевильная комедия о незадачливом холостяке, который решил найти невесту через брачное объявление.', 'https://s1.afisha.ru/mediastorage/44/3c/81ad2fbbc9df4064890d76793c44.jpg', 'Водевиль', 110, '12+', 7.9, 'Kassy.ru', NULL, '2026-07-11 23:02:23.717706+00'), (16, 'Холоп 3', 'movie', 'Финал народной трилогии: избалованный богатый наследник вновь оказывается на грани перевоспитания — на этот раз приключения забрасывают героев в эпоху Петра I.', 'https://static.kinoafisha.info/k/movie_posters/110/upload/movie_posters/1/1/1/8375111/147604663767.jpg', 'Комедия', 116, '12+', 6.6, 'Афиша.ру', NULL, '2026-07-11 23:50:10.871293+00'), (17, 'Колония', 'movie', 'На конференции по биотехнологиям происходит внезапный выброс неизвестного вируса, здание закрывают на карантин — и запертым внутри людям предстоит бороться за выживание.', 'https://www.kinonews.ru/insimgs/2026/poster/poster141264_3.webp', 'Боевик', 122, '18+', 7.4, 'Kino Mail', NULL, '2026-07-11 23:50:10.926693+00'), (18, 'Кодекс Данте', 'movie', 'Эзотерический детектив-кейпер по роману Ника Тошеса: букинист случайно завладевает рукописью Данте и оказывается втянут в опасную охоту с участием мафии и Ватикана.', 'https://static.kinoafisha.info/k/movie_posters/110/upload/movie_posters/4/3/7/8372734/800461579969.jpg', 'Драма', 115, '16+', 6.9, 'Кинопоиск Афиша', NULL, '2026-07-11 23:50:10.975314+00'), (19, 'Кабала святош', 'theater', 'Булгаковская пьеса о Мольере и всесильной кабале, решающей судьбы художников при дворе Короля-солнца — новая постановка МХТ с Константином Хабенским.', 'https://s3.afisha.ru/mediastorage/d4/41/9e12596fb9034eb8b525b39741d4.jpg', 'Драма', 170, '16+', 8.8, 'MXAT.ru', NULL, '2026-07-11 23:50:11.01337+00'), (20, 'Две Анны', 'theater', 'Балетный проект MuzArts — история в танце о двух великих женщинах XX столетия, представленная ведущими солистами российского балета.', 'https://live.mts.ru/image/536x360/dve-anny-4c8393ba-1f53-459f-b54b-5f6b6df41a20.jpg', 'Балет', 110, '12+', 9, 'Maly.ru', NULL, '2026-07-11 23:50:11.068653+00'), (21, 'Актриса', 'theater', 'Трагикомедия современного театра антрепризы о звезде сцены, которой предстоит заново найти себя за кулисами собственной славы.', 'https://s13.stc.all.kpcdn.net/afisha/msk/wp-content/uploads/sites/5/2025/01/img_20260126_1123051-600x600.jpg', 'Трагикомедия', 90, '16+', 9, 'Яндекс Афиша', NULL, '2026-07-11 23:50:11.107557+00'), (22, 'Пасть', 'movie', 'Компания друзей отправляется в круиз по диким озёрам Луизианы, желая увидеть редких животных в естественной среде — и становится дичью сама.', 'https://static.kinoafisha.info/k/movie_posters/110/upload/movie_posters/6/4/9/8384946/574544069493.jpg', 'Ужасы', 92, '18+', 6.2, 'Kinoteatr.ru', NULL, '2026-07-11 23:54:43.625574+00'), (23, 'Иллюзия убийства', 'movie', 'Испанский психологический триллер: похищенный брат возвращается домой с пугающими тайнами, и герою предстоит распутать клубок лжи ненадёжных рассказчиков.', 'https://leonardo.osnova.io/21e99680-fe3c-5853-81d7-77010a2c03db/-/scale_crop/592x/', 'Детектив', 108, '18+', 6.8, 'Lifehacker.ru', NULL, '2026-07-11 23:54:43.678192+00'), (24, 'Майкл', 'movie', 'Масштабный музыкальный байопик о жизни и творчестве короля поп-музыки Майкла Джексона — от вундеркинда из Гэри, Индиана, до самого известного артиста планеты.', 'https://s12.stc.all.kpcdn.net/afisha/msk/wp-content/uploads/sites/5/2023/01/kadr-iz-trejlera-filma-majkl-2026-1.jpg', 'Биография', 127, '18+', 8.1, 'Кинопоиск Афиша', NULL, '2026-07-11 23:54:43.717496+00'), (25, 'Мастер и Маргарита', 'theater', 'Рок-мюзикл по роману Булгакова: Москва, где сталкиваются Воланд и его свита, влюблённые Мастер и Маргарита, поэт Иван Бездомный и вся человеческая суета.', 'https://peterburg.center/sites/default/files/img/event_m/2021-12/2021-12-26_07-59-37.png', 'Мюзикл', 150, '16+', 8.9, 'Kuda-SPb.ru', NULL, '2026-07-11 23:54:43.757554+00'), (26, 'Лолита', 'theater', 'Хоррор-мюзикл по мотивам романа Набокова: мрачная и завораживающая история одержимости, рассказанная языком современного музыкального театра.', 'https://i2020.otzovik.com/2020/04/16/9838651/img/1279705_12608479_t.jpeg', 'Мюзикл', 140, '18+', 8.3, 'Otzovik.com', NULL, '2026-07-11 23:54:43.821503+00'), (27, 'Дон Кихот', 'theater', 'Гастроли Театра балета имени Л. Якобсона: искромётный испанский колорит и виртуозная классическая хореография в одном из самых зрелищных балетов репертуара.', 'https://cdn.kassir.ru/spb/poster_1280_392/f3/f39682ab2b3dfe883450b376495dd4b7.jpg', 'Балет', 135, '6+', 8.7, 'Alexandrinskytheatre.ru', NULL, '2026-07-11 23:54:43.846646+00'), (28, 'Женитьба', 'theater', 'Гоголевская комедия о нерешительном женихе Подколёсине, свахе и незадачливом сватовстве — острая сатира на страх перемен, разыгранная на исторической сцене.', 'https://s.afisha.ru/mediastorage/82/42/47e397fe9e71412db794feb14282.jpg', 'Комедия', 145, '12+', 8.4, 'Kassir.ru', NULL, '2026-07-11 23:54:43.872334+00'), (29, 'Когда я снова стану маленьким', 'theater', 'Музыкальный спектакль по произведениям Януша Корчака, лауреат «Золотой маски» — трогательная история о детстве, доверии и праве быть услышанным.', 'https://s2.afisha.ru/mediastorage/a9/c7/d989fcc3502c4d5ca7d8e315c7a9.jpg', 'Музыкальный спектакль', 80, '6+', 8.9, 'BDT.spb.ru', NULL, '2026-07-11 23:54:43.897186+00'), (30, 'Ничего не бойся, я с тобой', 'theater', 'Хит-мюзикл на песни легендарной группы «Секрет» — романтичная история любви, дружбы и рок-н-ролльной юности восьмидесятых.', 'https://cdn.lifehacker.ru/wp-content/uploads/2026/04/Ap5ZQMoLZ4PJXKAb__Rq6quQpvHRsVj5KWawbpJ3k4kVoCnFhkv__hiqlSh9sX_WdAOefn1O6Dszqwpg_btjiQ3D3D_uid0filenameD0BCD18ED0B7D0B8D0BAD0BB2022D09DD0B8D187D0B5D0B3D0BE20D0BDD0B520D0B1D0BED0B9D181D18F2C20_1776174970.jpg', 'Мюзикл', 150, '12+', 9.6, 'Яндекс Афиша', NULL, '2026-07-11 23:54:43.921757+00'), (31, 'Кабаре', 'theater', 'Постановка Евгения Писарева по легендарному мюзиклу — Берлин на пороге больших перемен, кабаре «Кит-Кэт-Клуб» и судьбы, которые история уже не пощадит.', 'https://s1.afisha.ru/mediastorage/48/f0/880b2cb7bc4a492a8911359ff048.jpg', 'Мюзикл', 165, '18+', 9, 'Theatreofnations.ru', NULL, '2026-07-11 23:54:43.966473+00'), (32, 'История игрушек 5', 'movie', 'Пятая часть легендарной франшизы Pixar — Вуди, Баз Лайтер и их друзья узнают, что смартфоны и планшеты стали новыми любимцами детей, и отправляются в трогательное приключение, чтобы доказать: настоящая дружба важнее любых гаджетов.', 'https://kino-teatr.ua/public/main/films/2026-04/x2_poster_69d27d2b93468.jpg', 'Мультфильм', 100, '6+', 7.5, 'Dvhab.ru', NULL, '2026-07-12 00:08:44.222086+00'), (33, 'Живая ярость', 'movie', 'Когда дочь мастера-ремесленника Ван Вэя похищает преступная группировка, тот самостоятельно отправляется на её поиски. Его единственным союзником становится Навин — неутомимый журналист, чья жена таинственно исчезла. Мужчинам из разных слоёв общества предстоит объединиться, чтобы вернуть близких.', 'https://resizer.mail.ru/p/66d42bfd-219d-53cb-a188-8099a82efb42/AQACiWS69HpXo8nOQn2yT6wa3l4C_u9duir_decE0FL8cPIK_H_igLNCs4BVlgKBvtebR451KqhT1U3nDlKkQ4rPSBk.jpg', 'Боевик', 110, '18+', 8.3, 'Newslab.ru', NULL, '2026-07-12 00:08:44.38388+00'), (34, 'Женщины Сергея Есенина, или Любовь хулигана', 'theater', 'Документальный спектакль, основанный на реальных событиях из жизни великого русского поэта Сергея Есенина и женщин, ставших его музами — драматичная история любви и творчества на фоне бурной эпохи.', 'https://kirovdramteatr.ru/media/show/164_f0eefd04bbfd4c85706758da94a553.jpg', 'Документальный спектакль', 120, '16+', 8.8, 'Habdrama.ru', NULL, '2026-07-12 00:08:44.406177+00'), (35, 'Сильва', 'theater', 'Оперетта Имре Кальмана о непростой любви оперной дивы и аристократа, готового ради избранницы бросить вызов сословным предрассудкам — одна из самых красивых и мелодичных опереточных историй XX века.', 'https://www.belcanto.ru/media/images/composition/16080416.jpg', 'Оперетта', 140, '12+', 8.6, 'Muzteatrkhv.ru', NULL, '2026-07-12 00:08:44.431812+00'), (36, 'Руки Вверх! Юбилейный тур', 'concert', 'Сергей Жуков и группа «Руки Вверх!» отмечают юбилей на большой сцене — все главные хиты devяностых и двухтысячных в новой концертной программе.', 'https://prostars.org/files/catalog/items/0/530x800/22/5e04ed3fb3999.png', 'Поп', 120, '6+', 8.8, 'KP.ru Афиша', NULL, '2026-07-12 00:40:57.555168+00'), (37, 'Елена Ваенга. Большой концерт', 'concert', 'Елена Ваенга представляет большую сольную программу — искренняя эстрада и авторские песни, ставшие визитной карточкой одной из самых ярких артисток страны.', 'https://kremlinpalace.org/images/events/1750163203.jpg', 'Эстрада', 130, '16+', 9, 'KP.ru Афиша', NULL, '2026-07-12 00:40:57.593208+00'), (38, 'Леонид Агутин с новой программой', 'concert', 'Леонид Агутин исполнит новую программу вместе с бэндом — от джазовых баллад до самых узнаваемых хитов последних тридцати лет.', 'https://pic.rtbcdn.ru/video/2025-12-04/45/f8/45f84e2f341f9e5e6334ca9ff94df0f3.jpg', 'Поп', 110, '6+', 8.7, 'KP.ru Афиша', NULL, '2026-07-12 00:40:57.62314+00'), (39, 'КняZz', 'concert', 'Рок-группа КняZz — готик-рок с оркестровым размахом и театральной подачей в исполнении Андрея Лефлера и его команды.', 'https://amdm.ru/cs/images/artist/250/19376.jpg', 'Рок', 100, '12+', 8.5, 'KP.ru Афиша', NULL, '2026-07-12 00:40:57.660017+00'), (40, 'Мари Краймбрери', 'concert', 'Мари Краймбрери исполнит свои главные хиты и новые песни в большом сольном концерте с полноценным живым звуком.', 'https://mkraimbrery.ru/wp-content/uploads/sites/15/mari-kraymbreri-afisha-i-bilety-na-kontsert.jpg', 'Поп', 105, '12+', 8.6, 'Mos-Kassir.ru', NULL, '2026-07-12 00:40:57.692703+00'), (41, 'Олег Газманов', 'concert', 'Олег Газманов представляет большую концертную программу из главных хитов десятилетий — «Морячка», «Есаул», «Москва» и многое другое.', 'https://gazmanov-oleg.ru/photos/gazmanov-taganrog.jpg', 'Поп', 115, '6+', 8.4, 'Afisha.org.ru', NULL, '2026-07-12 00:40:57.730159+00');

